<span class="line"><span style="color:#D4D4D4;">	</span><span style="color:#9CDCFE;">defaultClient</span><span style="color:#D4D4D4;"> := ddhttp.</span><span style="color:#DCDCAA;">NewClient</span><span style="color:#D4D4D4;">()</span></span>
